/**
 * STEP 0: Contract Deployment and Setup
 *
 * 컨트랙트 배포 및 초기 설정 컴포넌트
 * - Contract deployment
 * - Owner authorization
 * - Executor registration
 * - Vote Type configuration
 * - Artist registration
 */

import { BaseStep } from '../BaseStep';
import { WalletAdapter } from '../../../infrastructure/viem/WalletAdapter';
import { createPublicClient, createWalletClient, http, type Address } from 'viem';
import { opBNBTestnet } from 'viem/chains';
import { privateKeyToAccount } from 'viem/accounts';
import * as UIHelper from '../../utils/UIHelper';

// MainVoting Bytecode (embedded)
const MAINVOTING_BYTECODE = "" as const;

// MainVoting ABI (minimal for deployment and setup)
const SETUP_ABI = [
  'constructor(address initialOwner)',
  'function setExecutorSigner(address _executorSigner)',
  'function setVoteTypeName(uint8 voteType, string memory name)',
  'function setArtist(uint256 missionId, uint256 optionId, string memory name, bool allowed)',
] as const;

type StatusType = 'success' | 'error' | 'info';

/**
 * Step 0: Contract Deployment and Setup Component
 */
export class Step0Setup extends BaseStep {
  private deployerWallet: WalletAdapter | null = null;
  private deployedAddress: Address | null = null;

  /**
   * Render Step 0 UI
   */
  render(): string {
    return `
      <div id="step0" class="bg-white rounded-lg shadow p-6 mb-6 border-l-4 border-purple-500">
        <h2 class="text-xl font-semibold mb-4">
          <span class="step-badge bg-purple-500">STEP 0</span>
          Contract Deployment & Setup
        </h2>
        <p class="text-sm text-gray-600 mb-4">컨트랙트 배포 및 초기 설정을 진행합니다</p>

        <!-- Deployer Wallet -->
        <div class="mb-6 p-4 bg-purple-50 rounded-lg border border-purple-200">
          <h3 class="text-md font-semibold text-purple-800 mb-3">Deployer Wallet</h3>
          <label class="block text-sm font-medium text-gray-700 mb-2">Private Key (0x...)</label>
          <input
            type="text"
            id="deployerPrivateKey"
            class="w-full px-3 py-2 border rounded-md text-xs font-mono mb-2"
            placeholder="0x..."
          >
          <p class="text-xs text-gray-500">
            Address: <span id="deployerAddress" class="font-mono text-xs">-</span>
          </p>
          <button id="deployContractBtn" class="mt-3 bg-purple-500 text-white px-4 py-2 rounded-md hover:bg-purple-600">
            Deploy Contract
          </button>
          <div id="deployStatus" class="mt-3 hidden"></div>

          <!-- Deployed Address Display -->
          <div id="deployedAddressDisplay" class="mt-4 hidden p-3 bg-green-50 border border-green-200 rounded">
            <p class="text-sm font-semibold text-green-800 mb-1">Deployed Contract:</p>
            <p id="newContractAddress" class="text-xs font-mono break-all"></p>
            <button id="useDeployedAddressBtn" class="mt-2 text-sm bg-green-500 text-white px-3 py-1 rounded hover:bg-green-600">
              Use This Address
            </button>
          </div>
        </div>

        <!-- Owner Settings -->
        <div class="mb-6 p-4 bg-blue-50 rounded-lg border border-blue-200">
          <h3 class="text-md font-semibold text-blue-800 mb-3">Owner Settings</h3>
          <label class="block text-sm font-medium text-gray-700 mb-2">Owner Private Key (0x...)</label>
          <input
            type="text"
            id="ownerPrivateKey"
            class="w-full px-3 py-2 border rounded-md text-xs font-mono mb-2"
            placeholder="0x..."
          >
          <p class="text-xs text-gray-500">
            Address: <span id="ownerAddress" class="font-mono text-xs">-</span>
          </p>
        </div>

        <!-- Executor Registration -->
        <div class="mb-6 p-4 bg-yellow-50 rounded-lg border border-yellow-200">
          <h3 class="text-md font-semibold text-yellow-800 mb-3">Executor Registration</h3>
          <label class="block text-sm font-medium text-gray-700 mb-2">Executor Address</label>
          <input
            type="text"
            id="executorAddressToSet"
            class="w-full px-3 py-2 border rounded-md text-xs font-mono mb-2"
            placeholder="0x..."
          >
          <button id="setExecutorBtn" class="mt-2 bg-yellow-500 text-white px-4 py-2 rounded-md hover:bg-yellow-600">
            Set Executor
          </button>
          <div id="executorSetStatus" class="mt-3 hidden"></div>
        </div>

        <!-- Vote Type Names -->
        <div class="mb-6 p-4 bg-green-50 rounded-lg border border-green-200">
          <h3 class="text-md font-semibold text-green-800 mb-3">Vote Type Names</h3>
          <div class="grid grid-cols-2 gap-4">
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">Type 0 (Forget)</label>
              <input
                type="text"
                id="voteTypeName0"
                class="w-full px-3 py-2 border rounded-md text-sm"
                value="Forget"
              >
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">Type 1 (Remember)</label>
              <input
                type="text"
                id="voteTypeName1"
                class="w-full px-3 py-2 border rounded-md text-sm"
                value="Remember"
              >
            </div>
          </div>
          <button id="setVoteTypeBtn" class="mt-3 bg-green-500 text-white px-4 py-2 rounded-md hover:bg-green-600">
            Set Vote Types
          </button>
          <div id="voteTypeStatus" class="mt-3 hidden"></div>
        </div>

        <!-- Artist Registration -->
        <div class="mb-6 p-4 bg-pink-50 rounded-lg border border-pink-200">
          <h3 class="text-md font-semibold text-pink-800 mb-3">Artist Registration</h3>
          <div class="grid grid-cols-3 gap-4">
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">Mission ID</label>
              <input type="number" id="candidateMissionId" class="w-full px-3 py-2 border rounded-md" value="1">
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">Artist ID</label>
              <input type="number" id="candidateArtistId" class="w-full px-3 py-2 border rounded-md" value="1">
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">Name</label>
              <input type="text" id="candidateName" class="w-full px-3 py-2 border rounded-md" value="Artist A">
            </div>
          </div>
          <button id="registerArtistBtn" class="mt-3 bg-pink-500 text-white px-4 py-2 rounded-md hover:bg-pink-600">
            Register Artist
          </button>
          <div id="candidateStatus" class="mt-3 hidden"></div>
        </div>
      </div>
    `;
  }

  /**
   * Initialize event listeners
   */
  init(): void {
    super.init();
    this.attachEventListeners();
  }

  /**
   * Attach event listeners
   */
  private attachEventListeners(): void {
    // Deployer wallet input
    UIHelper.safeAddEventListener('deployerPrivateKey', 'input', () => {
      this.updateDeployerWallet();
    });

    // Deploy button
    UIHelper.safeAddEventListener('deployContractBtn', 'click', () => {
      void this.deployContract();
    });

    // Use deployed address button
    UIHelper.safeAddEventListener('useDeployedAddressBtn', 'click', () => {
      this.applyDeployedAddress();
    });

    // Owner wallet input
    UIHelper.safeAddEventListener('ownerPrivateKey', 'input', () => {
      this.updateOwnerWallet();
    });

    // Set executor button
    UIHelper.safeAddEventListener('setExecutorBtn', 'click', () => {
      void this.setExecutor();
    });

    // Set vote type button
    UIHelper.safeAddEventListener('setVoteTypeBtn', 'click', () => {
      void this.setVoteTypeNames();
    });

    // Register artist button
    UIHelper.safeAddEventListener('registerArtistBtn', 'click', () => {
      void this.registerArtist();
    });
  }

  /**
   * Update deployer wallet address display
   */
  private updateDeployerWallet(): void {
    const privateKey = UIHelper.getInputValue('deployerPrivateKey').trim();

    if (!privateKey) {
      this.deployerWallet = null;
      UIHelper.showValue('deployerAddress', '-');
      return;
    }

    try {
      this.deployerWallet = new WalletAdapter(privateKey as `0x${string}`);
      UIHelper.showValue('deployerAddress', this.deployerWallet.address);
    } catch (error) {
      console.error('Deployer wallet initialization failed:', error);
      this.deployerWallet = null;
      UIHelper.showValue('deployerAddress', '-');
    }
  }

  /**
   * Update owner wallet address display
   */
  private updateOwnerWallet(): void {
    const privateKey = UIHelper.getInputValue('ownerPrivateKey').trim();

    if (!privateKey) {
      this.state.setState({ ownerWallet: null });
      UIHelper.showValue('ownerAddress', '-');
      return;
    }

    try {
      const wallet = new WalletAdapter(privateKey as `0x${string}`);
      this.state.setState({ ownerWallet: wallet });
      UIHelper.showValue('ownerAddress', wallet.address);
    } catch (error) {
      console.error('Owner wallet initialization failed:', error);
      this.showStatus('Invalid private key', 'error', 'ownerWalletStatus');
      this.state.setState({ ownerWallet: null });
      UIHelper.showValue('ownerAddress', '-');
    }
  }

  /**
   * Deploy MainVoting contract
   */
  private async deployContract(): Promise<void> {
    try {
      if (!this.deployerWallet) {
        this.showStatus('Please enter deployer private key first', 'error', 'deployStatus');
        return;
      }

      this.showStatus('[DEPLOY] Deploying contract...', 'info', 'deployStatus');

      const account = privateKeyToAccount(UIHelper.getInputValue('deployerPrivateKey') as `0x${string}`);
      const walletClient = createWalletClient({
        account,
        chain: opBNBTestnet,
        transport: http(),
      });

      const publicClient = createPublicClient({
        chain: opBNBTestnet,
        transport: http(),
      });

      // Deploy contract with constructor arg (initialOwner)
      const hash = await walletClient.deployContract({
        abi: SETUP_ABI,
        bytecode: MAINVOTING_BYTECODE,
        args: [account.address],
      });

      this.showStatus(`[TX] Transaction sent. Waiting...\nTX: ${hash}`, 'info', 'deployStatus');

      // Wait for deployment
      const receipt = await publicClient.waitForTransactionReceipt({ hash });

      if (!receipt.contractAddress) {
        throw new Error('Contract address not found in receipt');
      }

      this.deployedAddress = receipt.contractAddress;

      // Update UI
      this.showStatus(`[SUCCESS] Deployment complete!\nAddress: ${this.deployedAddress}`, 'success', 'deployStatus');

      const displayEl = document.getElementById('deployedAddressDisplay');
      const addressEl = document.getElementById('newContractAddress');
      const useBtn = document.getElementById('useDeployedAddressBtn');

      if (displayEl) displayEl.classList.remove('hidden');
      if (addressEl) addressEl.textContent = this.deployedAddress;
      if (useBtn) useBtn.classList.remove('hidden');

      // Auto-apply deployed address
      this.applyDeployedAddress();

    } catch (error) {
      console.error('Contract deployment failed:', error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.showStatus(`[ERROR] Deployment failed: ${message}`, 'error', 'deployStatus');
    }
  }

  /**
   * Apply deployed address to contract address field
   */
  private applyDeployedAddress(): void {
    if (!this.deployedAddress) {
      console.error('No deployed address');
      return;
    }

    // Update contract address input
    UIHelper.setInputValue('contractAddress', this.deployedAddress);

    // Trigger input event for other components
    const contractInput = document.getElementById('contractAddress') as HTMLInputElement | null;
    contractInput?.dispatchEvent(new Event('input', { bubbles: true }));

    // Update state
    this.state.setState({ contractAddress: this.deployedAddress });

    this.showStatus(`[SUCCESS] Contract address updated: ${this.deployedAddress}`, 'success', 'deployStatus');
  }

  /**
   * Set executor signer
   */
  private async setExecutor(): Promise<void> {
    try {
      const { ownerWallet, contractAddress } = this.state.getState();

      if (!ownerWallet) {
        this.showStatus('Please enter Owner private key first', 'error', 'executorSetStatus');
        return;
      }

      if (!contractAddress) {
        this.showStatus('Please deploy or set contract address first', 'error', 'executorSetStatus');
        return;
      }

      const executorAddress = UIHelper.getInputValue('executorAddressToSet').trim();
      if (!executorAddress) {
        this.showStatus('Please enter Executor address', 'error', 'executorSetStatus');
        return;
      }

      this.showStatus('Setting executor...', 'info', 'executorSetStatus');

      const account = privateKeyToAccount(UIHelper.getInputValue('ownerPrivateKey') as `0x${string}`);
      const walletClient = createWalletClient({
        account,
        chain: opBNBTestnet,
        transport: http(),
      });

      const publicClient = createPublicClient({
        chain: opBNBTestnet,
        transport: http(),
      });

      const hash = await walletClient.writeContract({
        address: contractAddress,
        abi: SETUP_ABI,
        functionName: 'setExecutorSigner',
        args: [executorAddress as Address],
      });

      this.showStatus(`Transaction sent. Waiting... (${hash.substring(0, 10)}...)`, 'info', 'executorSetStatus');

      await publicClient.waitForTransactionReceipt({ hash });
      this.showStatus(`[SUCCESS] Executor set!\nTX: ${hash}`, 'success', 'executorSetStatus');

    } catch (error) {
      console.error('Set executor failed:', error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.showStatus(`[ERROR] ${message}`, 'error', 'executorSetStatus');
    }
  }

  /**
   * Set vote type names
   */
  private async setVoteTypeNames(): Promise<void> {
    try {
      const { ownerWallet, contractAddress } = this.state.getState();

      if (!ownerWallet) {
        this.showStatus('Please enter Owner private key first', 'error', 'voteTypeStatus');
        return;
      }

      if (!contractAddress) {
        this.showStatus('Please deploy or set contract address first', 'error', 'voteTypeStatus');
        return;
      }

      const name0 = UIHelper.getInputValue('voteTypeName0').trim();
      const name1 = UIHelper.getInputValue('voteTypeName1').trim();

      if (!name0 || !name1) {
        this.showStatus('Please enter both vote type names', 'error', 'voteTypeStatus');
        return;
      }

      this.showStatus('Setting vote type names...', 'info', 'voteTypeStatus');

      const account = privateKeyToAccount(UIHelper.getInputValue('ownerPrivateKey') as `0x${string}`);
      const walletClient = createWalletClient({
        account,
        chain: opBNBTestnet,
        transport: http(),
      });

      const publicClient = createPublicClient({
        chain: opBNBTestnet,
        transport: http(),
      });

      // Set type 0
      const hash0 = await walletClient.writeContract({
        address: contractAddress,
        abi: SETUP_ABI,
        functionName: 'setVoteTypeName',
        args: [0, name0],
      });

      this.showStatus(`Type 0 setting... (${hash0.substring(0, 10)}...)`, 'info', 'voteTypeStatus');
      await publicClient.waitForTransactionReceipt({ hash: hash0 });

      // Set type 1
      const hash1 = await walletClient.writeContract({
        address: contractAddress,
        abi: SETUP_ABI,
        functionName: 'setVoteTypeName',
        args: [1, name1],
      });

      this.showStatus(`Type 1 setting... (${hash1.substring(0, 10)}...)`, 'info', 'voteTypeStatus');
      await publicClient.waitForTransactionReceipt({ hash: hash1 });

      this.showStatus(`[SUCCESS] Vote type names set!\n0: ${name0}\n1: ${name1}`, 'success', 'voteTypeStatus');

    } catch (error) {
      console.error('Set vote type failed:', error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.showStatus(`[ERROR] ${message}`, 'error', 'voteTypeStatus');
    }
  }

  /**
   * Register artist
   */
  private async registerArtist(): Promise<void> {
    try {
      const { ownerWallet, contractAddress } = this.state.getState();

      if (!ownerWallet) {
        this.showStatus('Please enter Owner private key first', 'error', 'candidateStatus');
        return;
      }

      if (!contractAddress) {
        this.showStatus('Please deploy or set contract address first', 'error', 'candidateStatus');
        return;
      }

      const missionId = BigInt(UIHelper.getInputValue('candidateMissionId'));
      const artistId = BigInt(UIHelper.getInputValue('candidateArtistId'));
      const name = UIHelper.getInputValue('candidateName').trim();

      if (!name) {
        this.showStatus('Please enter artist name', 'error', 'candidateStatus');
        return;
      }

      this.showStatus('Registering artist...', 'info', 'candidateStatus');

      const account = privateKeyToAccount(UIHelper.getInputValue('ownerPrivateKey') as `0x${string}`);
      const walletClient = createWalletClient({
        account,
        chain: opBNBTestnet,
        transport: http(),
      });

      const publicClient = createPublicClient({
        chain: opBNBTestnet,
        transport: http(),
      });

      const hash = await walletClient.writeContract({
        address: contractAddress,
        abi: SETUP_ABI,
        functionName: 'setArtist',
        args: [missionId, artistId, name, true],
      });

      this.showStatus(`Transaction sent. Waiting... (${hash.substring(0, 10)}...)`, 'info', 'candidateStatus');

      await publicClient.waitForTransactionReceipt({ hash });
      this.showStatus(`[SUCCESS] Artist registered!\nName: ${name}\nMission ID: ${missionId}\nArtist ID: ${artistId}\nTX: ${hash}`, 'success', 'candidateStatus');

    } catch (error) {
      console.error('Register artist failed:', error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.showStatus(`[ERROR] ${message}`, 'error', 'candidateStatus');
    }
  }

  /**
   * Show status message
   */
  private showStatus(message: string, type: StatusType, elementId: string): void {
    const element = document.getElementById(elementId);
    if (!element) return;

    const statusType = type === 'info' ? 'loading' : type;
    UIHelper.showStatusWithIcon(elementId, message, statusType);
    element.style.whiteSpace = 'pre-line';
  }
}
